create table country(
	id			int NOT NULL,
	name		varchar(255) NOT NULL,
	PRIMARY KEY (id)
);
	
create table region(
	id			int NOT NULL,
	country_id	bigint not null REFERENCES country (id),
	name		varchar(255) NOT NULL,
	PRIMARY KEY (id)
);
	
create table city(
	id			int NOT NULL,
	region_id	bigint not null REFERENCES region (id),
	name		varchar(255) NOT NULL,
	PRIMARY KEY (id)
);

